module edge_counter(
    input        clk,
    input        rst_n,
    input        signal_in,
    output reg [7:0] edge_count
);

    reg signal_out_q;

    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            signal_out_q <= 1'b0;
            edge_count <= 8'b0;
        end
        else begin
            signal_out_q <= signal_in;
            if(signal_in & ~signal_out_q)
                edge_count <= edge_count + 1;
        end
    end

endmodule
